import math

def baby_giant_step(a: int, b: int, n: int) -> int | None:
    """
    Solves the discrete logarithm problem a^x = b (mod n) using the Baby-Step Giant-Step algorithm.

    Args:
        a: The base.
        b: The result.
        n: The modulus.

    Returns:
        The smallest non-negative integer x such that a^x = b (mod n),
        or None if no solution is found in the search range or if a modular inverse
        cannot be computed (e.g., if gcd(a, n) != 1).
    """
    if n <= 1:
        return None

    if b == 1:
        return 0

    if a == 0:
        if b == 0:
            return 1
        return None

    m = int(math.sqrt(n)) + 1

    baby_steps = {}
    current_val = 1
    for j in range(m):
        if current_val == b:
            return j
        baby_steps[current_val] = j
        current_val = (current_val * a) % n

    try:
        a_inv_m = pow(a, -m, n)
    except ValueError:
        return None

    y = b
    for k in range(m):
        if y in baby_steps:
            j = baby_steps[y]
            return j + k * m
        y = (y * a_inv_m) % n

    return None
